'use client'
import { cn } from '@cascivo/core'
import type { InputHTMLAttributes, ReactNode } from 'react'
import styles from './checkbox-card.module.css'

export interface CheckboxCardProps extends Omit<
  InputHTMLAttributes<HTMLInputElement>,
  'title' | 'onChange'
> {
  title: ReactNode
  description?: ReactNode
  onCheckedChange?: (checked: boolean) => void
  className?: string | undefined
}

export function CheckboxCard({
  title,
  description,
  checked,
  defaultChecked,
  disabled,
  onCheckedChange,
  className,
  ...props
}: CheckboxCardProps) {
  return (
    <label className={cn(styles['card'], className)} data-disabled={disabled || undefined}>
      <input
        type="checkbox"
        className={styles['input']}
        disabled={disabled}
        {...(checked !== undefined ? { checked } : { defaultChecked })}
        onChange={(e) => onCheckedChange?.(e.currentTarget.checked)}
        {...props}
      />
      <span className={styles['glyph']} aria-hidden="true">
        <svg viewBox="0 0 12 12" className={styles['check']}>
          <path d="M2.5 6.5 5 9l4.5-5.5" fill="none" stroke="currentColor" strokeWidth="1.5" />
        </svg>
      </span>
      <span className={styles['body']}>
        <span className={styles['title']}>{title}</span>
        {description && <span className={styles['description']}>{description}</span>}
      </span>
    </label>
  )
}

@layer cascivo.component {
  .card {
    display: flex;
    gap: var(--cascivo-space-3);
    align-items: flex-start;
    padding: var(--cascivo-space-4);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    background: var(--cascivo-color-bg);
    cursor: pointer;
    transition:
      border-color 120ms ease,
      background-color 120ms ease;
  }

  .card:hover:not([data-disabled]) {
    border-color: var(--cascivo-color-border-strong);
  }

  .card:has(input:checked) {
    border-color: var(--cascivo-color-accent);
    background: color-mix(in oklch, var(--cascivo-color-accent) 4%, var(--cascivo-color-bg));
  }

  .card:has(input:focus-visible) {
    box-shadow: var(--cascivo-focus-ring);
  }

  .card[data-disabled] {
    opacity: 0.5;
    cursor: not-allowed;
  }

  .input {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    overflow: hidden;
    clip-path: inset(50%);
    white-space: nowrap;
  }

  .glyph {
    flex: none;
    inline-size: 1rem;
    block-size: 1rem;
    margin-block-start: 2px;
    display: grid;
    place-items: center;
    border: 1px solid var(--cascivo-color-border-strong);
    border-radius: var(--cascivo-radius-indicator);
    color: transparent;
    transition: all 120ms ease;
  }

  .card:has(input:checked) .glyph {
    border-color: var(--cascivo-color-accent);
    background: var(--cascivo-color-accent);
    color: var(--cascivo-color-accent-foreground, oklch(1 0 0));
  }

  .check {
    inline-size: 0.75rem;
    block-size: 0.75rem;
  }

  .body {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
  }

  .title {
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
  }

  .description {
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
  }
}
